import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Rooms from './pages/Rooms';
import BookRoom from './pages/BookRoom';
import Reservations from './pages/Reservations';

export default function App() {
  return (
    <BrowserRouter>
      <Navbar />
      <Routes>
        <Route path='/' element={<Home />} />
        <Route path='/rooms' element={<Rooms />} />
        <Route path='/book-room' element={<BookRoom />} />
        <Route path='/reservations' element={<Reservations />} />
      </Routes>
    </BrowserRouter>
  );
}

import React from 'react';
import { NavLink } from 'react-router-dom';

export default function Navbar() {
  const linkStyle = ({ isActive }) => ({
    textDecoration: 'none',
    color: isActive ? '#0f172a' : '#64748b',
    fontWeight: isActive ? 700 : 500
  });

  return (
    <nav style={{ borderBottom: '1px solid #e2e8f0', background: '#fff' }}>
      <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '16px 24px', display: 'flex', justifyContent: 'space-between' }}>
        <h2 style={{ margin: 0 }}>StayEase</h2>
        <div style={{ display: 'flex', gap: '18px' }}>
          <NavLink to='/' style={linkStyle}>Home</NavLink>
          <NavLink to='/rooms' style={linkStyle}>Rooms</NavLink>
          <NavLink to='/book-room' style={linkStyle}>Book</NavLink>
          <NavLink to='/reservations' style={linkStyle}>Reservations</NavLink>
        </div>
      </div>
    </nav>
  );
}

import React from 'react';

export default function RoomCard({ room }) {
  return (
    <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '16px', background: '#fff' }}>
      <h3 style={{ marginTop: 0 }}>{room.room_type}</h3>
      <p style={{ color: '#64748b' }}>Status: {room.availability_status}</p>
      <p style={{ fontWeight: 700 }}>${room.price_per_night} / night</p>
      <button style={{ marginTop: '8px', padding: '10px 14px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff' }}>
        Select Room
      </button>
    </div>
  );
}

import React from 'react';

export default function Home() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <div style={{ background: '#f8fafc', border: '1px solid #e2e8f0', borderRadius: '18px', padding: '32px' }}>
        <h1>Comfortable stays for every trip</h1>
        <p style={{ color: '#475569', maxWidth: '680px' }}>
          Explore room options, book your stay, and manage your reservations from one clean booking portal.
        </p>
      </div>
    </div>
  );
}

import React from 'react';
import RoomCard from '../components/RoomCard';

const rooms = [
  { id: 1, room_type: 'Standard Room', price_per_night: 60, availability_status: 'Available' },
  { id: 2, room_type: 'Deluxe Room', price_per_night: 95, availability_status: 'Available' },
  { id: 3, room_type: 'Suite', price_per_night: 150, availability_status: 'Limited' }
];

export default function Rooms() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Rooms</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '18px' }}>
        {rooms.map(room => <RoomCard key={room.id} room={room} />)}
      </div>
    </div>
  );
}

import React from 'react';

export default function BookRoom() {
  return (
    <div style={{ maxWidth: '800px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Book Room</h1>
      <div style={{ border: '1px solid #e2e8f0', borderRadius: '14px', padding: '20px', background: '#fff', display: 'grid', gap: '14px' }}>
        <input placeholder='Guest Name' style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
        <select style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }}>
          <option>Select Room Type</option>
          <option>Standard Room</option>
          <option>Deluxe Room</option>
          <option>Suite</option>
        </select>
        <input type='date' style={{ padding: '12px', borderRadius: '10px', border: '1px solid #cbd5e1' }} />
        <button style={{ padding: '12px', borderRadius: '10px', border: 'none', background: '#0f172a', color: '#fff' }}>Confirm Reservation</button>
      </div>
    </div>
  );
}

import React from 'react';

const reservations = [
  { id: 1, guest_name: 'Ali Khan', room_type: 'Deluxe Room', check_in_date: '2026-03-26', status: 'Confirmed' },
  { id: 2, guest_name: 'Sara Ahmed', room_type: 'Suite', check_in_date: '2026-04-01', status: 'Pending' }
];

export default function Reservations() {
  return (
    <div style={{ maxWidth: '1100px', margin: '0 auto', padding: '32px 24px' }}>
      <h1>Reservations</h1>
      <table style={{ width: '100%', borderCollapse: 'collapse', border: '1px solid #e2e8f0' }}>
        <thead style={{ background: '#f8fafc' }}>
          <tr>
            <th style={{ padding: '12px', textAlign: 'left' }}>Guest</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Room</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Check-in</th>
            <th style={{ padding: '12px', textAlign: 'left' }}>Status</th>
          </tr>
        </thead>
        <tbody>
          {reservations.map(item => (
            <tr key={item.id}>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.guest_name}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.room_type}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.check_in_date}</td>
              <td style={{ padding: '12px', borderTop: '1px solid #e2e8f0' }}>{item.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/api/rooms')
def get_rooms():
    return jsonify({
        'rooms': [
            {'id': 1, 'room_type': 'Standard Room', 'price_per_night': 60, 'availability_status': 'Available'},
            {'id': 2, 'room_type': 'Deluxe Room', 'price_per_night': 95, 'availability_status': 'Available'},
            {'id': 3, 'room_type': 'Suite', 'price_per_night': 150, 'availability_status': 'Limited'}
        ]
    })

@app.route('/api/reservations')
def get_reservations():
    return jsonify({
        'reservations': [
            {'id': 1, 'guest_name': 'Ali Khan', 'room_type': 'Deluxe Room', 'check_in_date': '2026-03-26', 'status': 'Confirmed'},
            {'id': 2, 'guest_name': 'Sara Ahmed', 'room_type': 'Suite', 'check_in_date': '2026-04-01', 'status': 'Pending'}
        ]
    })

if __name__ == '__main__':
    app.run(debug=True)
